class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            if self.rank[root_i] < self.rank[root_j]:
                self.parent[root_i] = root_j
            elif self.rank[root_j] < self.rank[root_i]:
                self.parent[root_j] = root_i
            else:
                self.parent[root_j] = root_i
                self.rank[root_i] += 1
            return True
        return False

class Solution:
    def smallestStringWithSwaps(self, s: str, pairs: list[list[int]]) -> str:
        n = len(s)
        uf = UnionFind(n)

        for i, j in pairs:
            uf.union(i, j)

        groups = {}
        for i in range(n):
            root = uf.find(i)
            if root not in groups:
                groups[root] = []
            groups[root].append(i)

        result_list = [''] * n

        for root in groups:
            indices_in_component = groups[root]

            chars_in_component = [s[idx] for idx in indices_in_component]

            indices_in_component.sort()
            chars_in_component.sort()

            for i in range(len(indices_in_component)):
                original_pos = indices_in_component[i]
                sorted_char = chars_in_component[i]
                result_list[original_pos] = sorted_char

        return "".join(result_list)
